// ===== PARSE MQTT SENSOR DATA =====
const item = $input.first().json;

let payload;
try {
  if (item.message && typeof item.message === 'object') {
    payload = item.message;
  } else if (item.message && typeof item.message === 'string') {
    payload = JSON.parse(item.message);
  } else if (item.suhu !== undefined || item.tinggi_air !== undefined) {
    payload = item;
  } else {
    payload = item;
  }
} catch (e) {
  throw new Error('Gagal parse MQTT payload: ' + e.message + ' | Raw: ' + JSON.stringify(item));
}

const suhu = Math.round(parseFloat(payload.suhu || 0) * 100) / 100;
const kelembaban = Math.round(parseFloat(payload.kelembaban || 0) * 10) / 10;
const tinggi_air = Math.round(parseFloat(payload.tinggi_air || 0) * 10) / 10;
const pompa_on = payload.pompa === true || payload.pompa === 'true' || payload.pompa === 1 || parseInt(payload.pompa) === 1;
const mode_auto = payload.mode === undefined ? true : (payload.mode === 'AUTO' || payload.mode === 1 || payload.mode === true);

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const wibTime = new Date(now.getTime() + (7 * 60 * 60 * 1000));
const timestamp = `${pad(wibTime.getUTCDate())}-${pad(wibTime.getUTCMonth() + 1)}-${wibTime.getUTCFullYear()} ${pad(wibTime.getUTCHours())}:${pad(wibTime.getUTCMinutes())}:${pad(wibTime.getUTCSeconds())}`;

const is_critical = tinggi_air >= 20;
const mode_text = mode_auto ? 'AUTO' : 'MANUAL';

const staticData = $getWorkflowStaticData('global');
const nowMs = Date.now();
const lastAlertTime = staticData.lastCriticalAlertTime || 0;
const throttle_ms = 15000;
const can_alert = (nowMs - lastAlertTime) > throttle_ms;

if (is_critical && can_alert) {
  staticData.lastCriticalAlertTime = nowMs;
}

return [{
  json: {
    timestamp, suhu, kelembaban, tinggi_air,
    pompa_status: pompa_on ? 'ON' : 'OFF',
    mode: mode_text,
    is_critical,
    can_send_alert: is_critical && can_alert,
    esp32_timestamp: payload.timestamp || 0
  }
}];

const text = $input.first().json.message.text || '';
const isStart = text.toLowerCase() === '/start';

let replyText = '';

if (isStart) {
  replyText = `🌿 <b>Selamat datang di Smart Hydroponic Bot!</b> 🌿
━━━━━━━━━━━━━━━━━━━━
Halo! Saya adalah asisten pintar untuk memantau dan mengontrol sistem hidroponik Anda secara real-time.

💡 Ketik /help untuk melihat <b>daftar lengkap perintah</b> yang tersedia.`;
} else {
  replyText = `📋 <b>DAFTAR PERINTAH BOT</b>
━━━━━━━━━━━━━━━━━━━━

📊 <b>/status</b>
Lihat laporan sensor real-time:
suhu, kelembaban, tinggi air, status pompa, dan mode sistem.

⚙️ <b>/auto</b>
Aktifkan mode <b>OTOMATIS</b>.
Pompa dikontrol otomatis berdasarkan sensor.

🔧 <b>/manual</b>
Aktifkan mode <b>MANUAL</b>.
Kontrol pompa secara langsung.

✅ <b>/pompaon</b>
Nyalakan pompa secara manual.
<i>(Hanya aktif saat mode MANUAL)</i>

❌ <b>/pompaoff</b>
Matikan pompa secara manual.
<i>(Hanya aktif saat mode MANUAL)</i>

❓ <b>/help</b>
Tampilkan daftar perintah ini.
━━━━━━━━━━━━━━━━━━━━
💬 Anda juga bisa <b>bertanya bebas</b> seputar kondisi sistem hidroponik Anda!`;
}

return [{ json: { replyText, chatId: $input.first().json.message.chat.id } }];
